class Solution {
public:
    int maximumLength(string s) {
        int maxLen = -1;
        for (char c = 'a'; c <= 'z'; ++c) {
            int count = 0;
            int currLen = 0;
            for (char ch : s) {
                if (ch == c) {
                    ++currLen;
                } else {
                    currLen = 0;
                }
                if (currLen > 0 && currLen <= s.size() - 2) {
                    count += (s.find(string(currLen, c)) != string::npos && 
                              s.find(string(currLen, c), s.find(string(currLen, c)) + 1) != string::npos);
                }
            }
            if (count >= 3) {
                maxLen = max(maxLen, currLen);
            }
        }
        return maxLen;
    }
};
